import React, { useEffect, useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Navbar from './components/Layout/Navbar';
import Footer from './components/Layout/Footer';
import Home from './pages/Home';
import Login from './components/Auth/Login';
import Register from './components/Auth/Register';
import PatientDashboard from './components/Patient/Dashboard';
import DoctorList from './components/Patient/DoctorList';
import BookConsultation from './components/Patient/BookConsultation';
import ConsultationHistory from './components/Patient/ConsultationHistory';
import HealthRecords from './components/Patient/HealthRecords';
import SymptomChecker from './components/SymptomChecker/SymptomForm';
import PharmacyLocator from './components/Pharmacy/PharmacyLocator';
import DoctorDashboard from './components/Doctor/DoctorDashboard';
import Profile from './pages/Profile';
import './styles/global.css';

const PrivateRoute = ({ children, isAuthenticated }) => {
  return isAuthenticated ? children : <Navigate to="/login" />;
};

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [user, setUser] = useState(null);

  useEffect(() => {
    const token = localStorage.getItem('token');
    const userData = localStorage.getItem('user');
    if (token && userData) {
      setIsAuthenticated(true);
      setUser(JSON.parse(userData));
    }
  }, []);

  const handleLogin = (token, userData) => {
    localStorage.setItem('token', token);
    localStorage.setItem('user', JSON.stringify(userData));
    setIsAuthenticated(true);
    setUser(userData);
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    setIsAuthenticated(false);
    setUser(null);
  };

  return (
    <Router>
      <Navbar isAuthenticated={isAuthenticated} user={user} onLogout={handleLogout} />
      <main style={{ minHeight: '80vh' }}>
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/login" element={<Login onLogin={handleLogin} />} />
          <Route path="/register" element={<Register onLogin={handleLogin} />} />
          
          <Route
            path="/dashboard"
            element={
              <PrivateRoute isAuthenticated={isAuthenticated}>
                {user?.role === 'doctor' ? <DoctorDashboard /> : <PatientDashboard />}
              </PrivateRoute>
            }
          />

          <Route path="/doctors" element={<DoctorList />} />
          <Route
            path="/book-consultation/:doctorId"
            element={
              <PrivateRoute isAuthenticated={isAuthenticated}>
                <BookConsultation />
              </PrivateRoute>
            }
          />
          <Route
            path="/consultations"
            element={
              <PrivateRoute isAuthenticated={isAuthenticated}>
                <ConsultationHistory />
              </PrivateRoute>
            }
          />
          <Route
            path="/health-records"
            element={
              <PrivateRoute isAuthenticated={isAuthenticated}>
                <HealthRecords />
              </PrivateRoute>
            }
          />
          <Route path="/symptom-checker" element={<SymptomChecker />} />
          <Route path="/pharmacies" element={<PharmacyLocator />} />
          <Route
            path="/profile"
            element={
              <PrivateRoute isAuthenticated={isAuthenticated}>
                <Profile user={user} />
              </PrivateRoute>
            }
          />
        </Routes>
      </main>
      <Footer />
    </Router>
  );
}

export default App;
